def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Group triples by subject and process them in a more natural order
    sentences = []

    for subject, triples_list in subject_map.items():
        # Extract key attributes for natural sentence construction
        city_served = None
        location = None
        country = None
        elevation_m = None
        elevation_ft = None
        runway_length = None
        runway_name = None
        runway_surface = None
        operating_org = None
        owner = None
        iata = None
        icao = None
        first_runway_length_ft = None
        first_runway_surface = None
        third_runway_length_ft = None
        fourth_runway_surface = None
        fifth_runway_number = None
        fifth_runway_surface = None
        native_name = None
        capital = None
        language = None
        leader = None
        is_part_of = None
        other_attrs = []

        for predicate, obj in triples_list:
            if predicate == "cityServed":
                city_served = obj
            elif predicate == "location":
                location = obj
            elif predicate == "country":
                country = obj
            elif predicate == "elevationAboveTheSeaLevel":
                elevation_m = obj
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation_ft = obj
            elif predicate == "runwayLength":
                runway_length = obj
            elif predicate == "runwayName":
                runway_name = obj
            elif predicate == "runwaySurfaceType":
                runway_surface = obj
            elif predicate == "operatingOrganisation":
                operating_org = obj
            elif predicate == "owner":
                owner = obj
            elif predicate == "iataLocationIdentifier":
                iata = obj
            elif predicate == "icaoLocationIdentifier":
                icao = obj
            elif predicate == "1stRunwayLengthFeet":
                first_runway_length_ft = obj
            elif predicate == "1stRunwaySurfaceType":
                first_runway_surface = obj
            elif predicate == "3rdRunwayLengthFeet":
                third_runway_length_ft = obj
            elif predicate == "4thRunwaySurfaceType":
                fourth_runway_surface = obj
            elif predicate == "5thRunwayNumber":
                fifth_runway_number = obj
            elif predicate == "5thRunwaySurfaceType":
                fifth_runway_surface = obj
            elif predicate == "nativeName":
                native_name = obj
            elif predicate == "capital":
                capital = obj
            elif predicate == "language":
                language = obj
            elif predicate == "leader":
                leader = obj
            elif predicate == "isPartOf":
                is_part_of = obj
            else:
                other_attrs.append((predicate, obj))

        # Build a natural sentence structure
        parts = []

        # Start with the main subject
        base = subject

        # Add location information
        if location and country:
            base += f" is located in {location}, {country}"
        elif location:
            base += f" is located in {location}"
        elif country:
            base += f" is in {country}"

        # Add city served
        if city_served:
            if location:
                base += f", serving {city_served}"
            else:
                base += f" serves {city_served}"

        # Add elevation
        if elevation_m:
            parts.append(f"has an elevation of {elevation_m} metres above sea level")
        elif elevation_ft:
            parts.append(f"has an elevation of {elevation_ft} feet above sea level")

        # Add runway information
        if runway_length:
            parts.append(f"has a runway length of {runway_length} metres")
        if runway_name:
            parts.append(f"has a runway named {runway_name}")
        if runway_surface:
            parts.append(f"has a runway surface type of {runway_surface}")

        # Add operating organization
        if operating_org:
            parts.append(f"is operated by {operating_org}")

        # Add owner
        if owner:
            parts.append(f"is owned by {owner}")

        # Add identifiers
        if iata:
            parts.append(f"has an IATA code of {iata}")
        if icao:
            parts.append(f"has an ICAO code of {icao}")

        # Add first runway info
        if first_runway_length_ft:
            parts.append(f"has a first runway of {first_runway_length_ft} feet")
        if first_runway_surface:
            parts.append(f"with a first runway surface of {first_runway_surface}")

        # Add third runway info
        if third_runway_length_ft:
            parts.append(f"has a third runway of {third_runway_length_ft} feet")
        if fourth_runway_surface:
            parts.append(f"has a fourth runway surface of {fourth_runway_surface}")
        if fifth_runway_number:
            parts.append(f"has a fifth runway numbered {fifth_runway_number}")
        if fifth_runway_surface:
            parts.append(f"with a fifth runway surface of {fifth_runway_surface}")

        # Add native name
        if native_name:
            parts.append(f"also known as {native_name}")

        # Add administrative info
        if is_part_of:
            parts.append(f"is part of {is_part_of}")

        # Add country-level info (if country is the subject)
        if country and capital:
            parts.append(f"whose capital is {capital}")
        if country and language:
            parts.append(f"where the official language is {language}")
        if country and leader:
            parts.append(f"led by {leader}")

        # Combine base with parts
        if parts:
            sentence = base + ". " + " ".join(parts)
        else:
            sentence = base + "."

        sentences.append(sentence)

    # Join all subject sentences with " and " for multiple subjects
    return " and ".join(sentences)

